func calculateShipping(weight float64, zone int) float64 {
    if zone == 1 {
        return weight * 2.5 + 3.99
    } else if zone == 2 {
        return weight * 3.1 + 5.49
    } else if zone == 3 {
        return weight * 4.0 + 7.99
    }
    return weight * 5.5 + 12.99
}

def process_payment(amount, currency, user):
    if user is not None:
        if user.is_active:
            if amount > 0:
                if currency in SUPPORTED_CURRENCIES:
                    charge = stripe.charge(amount, currency)
                    return charge
                else:
                    raise ValueError('Unsupported currency')
            else:
                raise ValueError('Amount must be positive')
        else:
            raise ValueError('User is inactive')
    else:
        raise ValueError('User required')

interface ApiResponse<T> {
    data: T;
    error: string | null;
}

async function fetchUser(id: string): Promise<ApiResponse<User>> {
    const response: ApiResponse<User> = await api.get<ApiResponse<User>>(`/users/${id}`);
    return response;
}

def build_csv(rows):
    output = ''
    for row in rows:
        line = ''
        for value in row:
            line = line + str(value) + ','
        output = output + line.rstrip(',') + '\n'
    return output

func (s *OrderService) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*Order, error) {
    if err := s.db.Begin(); err != nil {
        log.Printf("failed to begin tx: %v", err)
        return nil, err
    }
    order, err := s.repo.Insert(ctx, req)
    if err != nil {
        log.Printf("failed to insert order: %v", err)
        return nil, err
    }
    if err := s.inventory.Reserve(ctx, req.Items); err != nil {
        log.Printf("failed to reserve inventory: %v", err)
        return nil, err
    }
    return order, nil
}

